#include <bits/stdc++.h>
using namespace std;

int main() {
    string s;
    cin >> s;
    int l = 0, r = s.size() - 1;
    bool isPal = true;
    while (l < r) {
        if (s[l] != s[r]) {
            isPal = false;
            break;
        }
        l++; r--;
    }
    cout << (isPal ? "True" : "False");
    return 0;
}

code.C:
#include <stdio.h>
#include <string.h>

int main() {
    char s[1000005];
    if (scanf("%1000000s", s) != 1) return 0;
    int l = 0, r = strlen(s) - 1;
    int isPal = 1;
    while (l < r) {
        if (s[l] != s[r]) {
            isPal = 0;
            break;
        }
        l++;
        r--;
    }
    printf(isPal ? "True\n" : "False\n");
    return 0;
}

code.Java:
import java.util.*;
import java.lang.*;
import java.io.*;

class Codechef
{
    public static void main (String[] args) throws java.lang.Exception
    {
        Scanner sc = new Scanner(System.in);
        String s = sc.next();
        int l = 0, r = s.length() - 1;
        boolean isPal = true;

        while(l < r){
            if(s.charAt(l) != s.charAt(r)){
                isPal = false;
                break;
            }
            l++;
            r--;
        }

        System.out.println(isPal ? "True" : "False");
    }
}

